"use client";

import { useEffect, useMemo, useState } from "react";
import { useParams, useRouter } from "next/navigation";
import Link from "next/link";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Tabs, TabsContent, TabsList, TabsTrigger } from "@/components/ui/tabs";
import { Badge } from "@/components/ui/badge";
import { Button } from "@/components/ui/button";
import { Label } from "@/components/ui/label";
import { Input } from "@/components/ui/input";
import { Textarea } from "@/components/ui/textarea";
import { ChevronLeft, Star, Mail, Phone, User as UserIcon } from "lucide-react";

const PROVIDERS_STORAGE_KEY = "adminProviders";

type ProviderStatus = "active" | "inactive" | "suspended";

type Provider = {
  id: string;
  name: string;
  email: string;
  phone: string;
  specialization: string;
  rating: number;
  completedJobs: number;
  status: ProviderStatus;
  joinedDate: string;
};

export default function ProviderProfilePage() {
  const params = useParams<{ id: string }>();
  const router = useRouter();
  const [provider, setProvider] = useState<Provider | null>(null);
  const id = params?.id;

  useEffect(() => {
    if (!id || typeof window === "undefined") return;
    try {
      const stored = localStorage.getItem(PROVIDERS_STORAGE_KEY);
      if (stored) {
        const list: Provider[] = JSON.parse(stored);
        const found = list.find((p) => String(p.id) === String(id));
        if (found) setProvider(found);
      }
    } catch {}
  }, [id]);

  const initials = useMemo(() => {
    if (!provider?.name) return "?";
    const parts = provider.name.split(" ");
    return parts.slice(0, 2).map((p) => p[0]?.toUpperCase()).join("");
  }, [provider]);

  if (!provider) {
    return (
      <div className="space-y-4">
        <div className="text-sm text-muted-foreground">Loading provider...</div>
        <Button variant="outline" onClick={() => router.push("/admin/providers")}>Back to Providers</Button>
      </div>
    );
  }

  const statusBadge = (status: ProviderStatus) => {
    const styles: Record<ProviderStatus, string> = {
      active: "bg-green-100 text-green-700 dark:bg-green-900/20 dark:text-green-400",
      inactive: "bg-gray-100 text-gray-700 dark:bg-gray-900/20 dark:text-gray-400",
      suspended: "bg-red-100 text-red-700 dark:bg-red-900/20 dark:text-red-400",
    };
    return (
      <Badge variant="outline" className={styles[status]}>
        {status.charAt(0).toUpperCase() + status.slice(1)}
      </Badge>
    );
  };

  return (
    <div className="space-y-6">
      <div className="flex items-center justify-between">
        <div className="flex items-center gap-2">
          <Link href="/admin/providers" aria-label="Back to Providers" className="inline-flex items-center justify-center h-8 w-8 rounded-md hover:bg-muted">
            <ChevronLeft className="h-5 w-5" />
          </Link>
          <h2 className="text-xl font-semibold">{provider.name}</h2>
        </div>
        <div className="flex items-center gap-3">
          <Button
            className="text-white"
            onClick={() => router.push("/admin/add-booking")}
            style={{ background: "linear-gradient(135deg, #00BCD4 0%, #00D4E8 100%)" }}
          >
            New Booking
          </Button>
        </div>
      </div>

      <Card>
        <CardContent className="pt-6">
          <div className="flex flex-col md:flex-row md:items-start md:justify-between gap-6">
            <div className="flex items-start gap-4 flex-1">
              <div className="h-24 w-24 md:h-28 md:w-28 rounded-full bg-cyan-100 text-cyan-700 flex items-center justify-center font-semibold text-xl md:text-2xl">
                {initials}
              </div>
              <div className="space-y-1 text-sm">
                <div className="flex items-center gap-2">
                  <Mail className="h-4 w-4 text-muted-foreground" />
                  <a href={`mailto:${provider.email}`} className="text-cyan-700 hover:underline">{provider.email}</a>
                </div>
                <div className="flex items-center gap-2">
                  <Phone className="h-4 w-4 text-muted-foreground" />
                  <span>{provider.phone}</span>
                </div>
                <div><span className="font-medium">Specialization:</span> {provider.specialization}</div>
                <div className="flex items-center gap-1"><Star className="h-4 w-4 fill-yellow-400 text-yellow-400" /><span className="font-medium">{provider.rating}</span></div>
                <div><span className="font-medium">Completed Jobs:</span> {provider.completedJobs}</div>
                <div><span className="font-medium">Joined:</span> {provider.joinedDate}</div>
                <div><span className="font-medium">Status:</span> {statusBadge(provider.status)}</div>
              </div>
            </div>
            <div className="w-full md:w-[420px]">
              <div className="grid grid-cols-1 sm:grid-cols-2 gap-3">
                <Button variant="outline" className="justify-start rounded-md bg-slate-200 text-slate-800 hover:bg-slate-300 dark:bg-slate-800/60 dark:text-slate-200">Message</Button>
                <Button variant="outline" className="justify-start rounded-md bg-slate-200 text-slate-800 hover:bg-slate-300 dark:bg-slate-800/60 dark:text-slate-200">Assign Job</Button>
              </div>
            </div>
          </div>
        </CardContent>
      </Card>

      <Tabs defaultValue="profile" className="w-full">
        <TabsList className="w-full justify-start gap-2 bg-muted/40 p-0 h-auto rounded-none border-b border-slate-200">
          <TabsTrigger value="profile" className="rounded-none px-3 py-3 text-slate-600 data-[state=active]:font-semibold data-[state=active]:text-slate-900 data-[state=active]:border-b-2 data-[state=active]:border-cyan-600">Profile</TabsTrigger>
          <TabsTrigger value="notes" className="rounded-none px-3 py-3 text-slate-600 data-[state=active]:font-semibold data-[state=active]:text-slate-900 data-[state=active]:border-b-2 data-[state=active]:border-cyan-600">Notes</TabsTrigger>
        </TabsList>

        <TabsContent value="profile">
          <Card>
            <CardHeader>
              <CardTitle>Basic Information</CardTitle>
            </CardHeader>
            <CardContent className="space-y-4">
              <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                <div>
                  <Label>Name</Label>
                  <Input value={provider.name} readOnly />
                </div>
                <div>
                  <Label>Email</Label>
                  <Input value={provider.email} readOnly />
                </div>
                <div>
                  <Label>Phone</Label>
                  <Input value={provider.phone} readOnly />
                </div>
                <div>
                  <Label>Specialization</Label>
                  <Input value={provider.specialization} readOnly />
                </div>
                <div>
                  <Label>Rating</Label>
                  <Input value={String(provider.rating)} readOnly />
                </div>
                <div>
                  <Label>Completed Jobs</Label>
                  <Input value={String(provider.completedJobs)} readOnly />
                </div>
                <div>
                  <Label>Status</Label>
                  <Input value={provider.status} readOnly />
                </div>
                <div>
                  <Label>Joined Date</Label>
                  <Input value={provider.joinedDate} readOnly />
                </div>
              </div>
            </CardContent>
          </Card>
        </TabsContent>

        <TabsContent value="notes">
          <Card>
            <CardHeader>
              <CardTitle>Notes</CardTitle>
            </CardHeader>
            <CardContent>
              <Textarea placeholder="Add notes about this provider" className="min-h-[160px]" />
            </CardContent>
          </Card>
        </TabsContent>
      </Tabs>
    </div>
  );
}
